{
  "grammar": [
    {
      "pattern": "Subject + 長得 / 看起來 + Adjective",
      "structure": ["Subject", "長得/看起來", "Adjective"],
      "explanation_en": "Use 長得 to describe inherent physical traits (height, build, etc.) and 看起來 for perceived appearance or impression.",
      "title": "Describing Appearance with 長得 and 看起來",
      "meaning": "Describing how someone looks",
      "when_to_use": ["Describing height, build, or facial features", "Giving first impressions of someone's appearance"],
      "when_not_to_use": ["Describing personality (use 個性 instead)", "Describing temporary states like clothing (use 穿著)"],
      "pragmatic_notes": "In Taiwan, 長得 is common for physical traits; 看起來 is softer and often used for compliments like '你看起來很年輕'.",
      "word_order_notes": "Adjective always comes after 長得 or 看起來, never before.",
      "english_contrast": "English says 'He is tall' directly; Chinese requires 長得 before the adjective.",
      "korean_contrast": "Korean uses '~이/가 키가 크다' structure; Chinese uses 長得 + adjective.",
      "negative_examples": [
        {
          "text": "他高長得。",
          "error": "Adjective must come after 長得, not before."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他長得高。",
          "error": "Correct! But if you meant '他很高', that's a different structure. 長得高 is fine for height."
        }
      ],
      "transformation_drills": ["Change '他很高' to '他長得很高'", "Change '她看起來很年輕' to '她長得很年輕'"],
      "production_drills": ["Describe your friend's height using 長得", "Describe how someone seems today using 看起來"],
      "common_error_patterns": ["Omitting 得 after 長", "Using 長得 for personality"],
      "repair_feedback": {
        "word_order": "Remember: 長得/看起來 + adjective, not adjective + 長得/看起來.",
        "politeness": "Using 看起來 is more polite for compliments than direct 長得.",
        "vocabulary": "Use 長得 for physical traits, 看起來 for impressions."
      }
    },
    {
      "pattern": "Subject + 很 + Adjective (for personality)",
      "structure": ["Subject", "很", "Adjective"],
      "explanation_en": "Use 很 before adjectives to describe personality traits. 很 is neutral here, not meaning 'very'.",
      "title": "Describing Personality with 很 + Adjective",
      "meaning": "Describing someone's personality",
      "when_to_use": ["Describing character traits like 友善, 幽默, 認真", "Making general statements about someone's nature"],
      "when_not_to_use": ["Describing physical appearance (use 長得)", "Emphasizing 'very' (use 非常 or 很 with stress)"],
      "pragmatic_notes": "In Taiwan, 很 is often used as a linking verb, not intensifier. Saying '他友善' sounds incomplete; '他很友善' is natural.",
      "word_order_notes": "Adjective always follows 很, never before the subject.",
      "english_contrast": "English says 'He is friendly'; Chinese requires 很 before the adjective: '他很友善'.",
      "korean_contrast": "Korean uses '그는 친절해요' without a separate word; Chinese needs 很.",
      "negative_examples": [
        {
          "text": "他友善。",
          "error": "Missing 很 makes the sentence sound unnatural or incomplete."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他很友善。",
          "error": "This is correct! But if you meant 'very friendly', stress 很 in speech."
        }
      ],
      "transformation_drills": ["Add 很 to '他聰明' to make it natural", "Change '她很認真' to a question form"],
      "production_drills": ["Describe your teacher's personality using 很 + adjective", "Say your friend is funny using 幽默"],
      "common_error_patterns": ["Omitting 很 before adjectives", "Using 很 for physical traits instead of 長得"],
      "repair_feedback": {
        "word_order": "Always put 很 before the adjective, not after.",
        "politeness": "Using 很 is standard; omitting it can sound blunt.",
        "vocabulary": "Use personality adjectives like 友善, 幽默, 認真 with 很."
      }
    },
    {
      "pattern": "那個人 + 是 + 誰 / 我朋友 / 他",
      "structure": ["那個人", "是", "Identifier"],
      "explanation_en": "Use 那個人 to refer to a specific person, then identify them with 是.",
      "title": "Identifying People with 那個人",
      "meaning": "Identifying a specific person",
      "when_to_use": ["Pointing out someone in a group", "Asking or answering who someone is"],
      "when_not_to_use": ["Describing appearance (use 長得)", "Talking about yourself (use 我)"],
      "pragmatic_notes": "In Taiwan, 那個人 is common in casual conversation. For politeness, add 請問 before questions.",
      "word_order_notes": "那個人 comes first, then 是, then the identifier.",
      "english_contrast": "English says 'That person is my friend'; Chinese order is same: 那個人是我朋友.",
      "korean_contrast": "Korean uses '그 사람은 내 친구예요'; Chinese uses 那個人 + 是.",
      "negative_examples": [
        {
          "text": "是那個人我朋友。",
          "error": "那個人 must come before 是, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "那個人是我朋友。",
          "error": "This is correct! But if you meant 'That tall person', use 那個人長得很高."
        }
      ],
      "transformation_drills": ["Change '那個人是我朋友' to a question", "Replace '我朋友' with '他'"],
      "production_drills": ["Point to someone and ask who they are", "Identify a person in a photo using 那個人"],
      "common_error_patterns": ["Using 這 instead of 那 for distant people", "Omitting 是"],
      "repair_feedback": {
        "word_order": "那個人 + 是 + identifier, not identifier + 是 + 那個人.",
        "politeness": "Add 請問 for polite questions: '請問那個人是誰？'",
        "vocabulary": "Use 那個人 for specific people, not for objects."
      }
    }
  ]
}
